// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Display tab 評価結果', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Display tab 評価結果', async function() {
    await driver.get("http://localhost:4200/user/list-evaluation");
    await driver.manage().window().setRect({ width: 1936, height: 1056 });
    await driver.findElement(By.css(".ant-layout-content")).click();
    await driver.findElement(By.css(".ant-btn-primary > span")).click();
    await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(2)")).click();
    assert(await driver.findElement(By.css(".ant-card-body > .ant-typography")).getText() == "評価結果");
    assert(await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(1)")).getText() == "本人");
    assert(await driver.findElement(By.css(".ant-table-wrapper:nth-child(2) .ant-table-thead:nth-child(2) .ant-table-cell:nth-child(2)")).getText() == "部門評価");
    assert(await driver.findElement(By.css(".ant-table-wrapper:nth-child(2) .ant-table-thead:nth-child(2) .ant-table-cell:nth-child(3)")).getText() == "個人評価");
  });
});
